import json
import re

# Load Europe articles metadata
file_path = locals()['var_functions.query_db:6']
with open(file_path, 'r') as f:
    europe_articles = json.load(f)

# Create year mapping
article_to_year = {}
for article in europe_articles:
    article_to_year[int(article['article_id'])] = int(article['publication_date'][:4])

# Group article IDs by year
articles_by_year = {}
for article_id, year in article_to_year.items():
    if year not in articles_by_year:
        articles_by_year[year] = []
    articles_by_year[year].append(article_id)

print('__RESULT__:')
print(json.dumps({
    'year_range': '2010-2020',
    'articles_per_year': {year: len(ids) for year, ids in sorted(articles_by_year.items())},
    'total_articles': sum(len(ids) for ids in articles_by_year.values())
}))

